from collections import Counterclass PersonInfo:    def __init__(self, name, age, *otdel):        self.name = name        self.age = age        self.otdel = otdel    def short_name(self):        inp = self.name.split()        return f'{inp[1]} {inp[0][0]}.'    def path_deps(self):        return ' --> '.join(self.otdel)    def new_salary(self):        otdel_work = ''.join(self.otdel)        sum_letter_otdel = Counter(otdel_work).most_common(3)        sum_letter = sum_letter_otdel[0][1] + sum_letter_otdel[1][1] + sum_letter_otdel[2][1]        return 1337 * self.age * sum_letterfirst_person = PersonInfo('Александр Шленский', 32, 'Разработка', 'УК', 'Автотесты')fourth_person = PersonInfo('Иван Иванов', 26, 'Разработка')second_person = PersonInfo('Пётр Валерьев', 47, 'Разработка', 'УК')third_person = PersonInfo('Макар Артуров', 51, 'Разработка', 'УК', 'Нефункциональное тестирование', 'Автотестирование')data = [first_person.short_name,        second_person.short_name,        third_person.short_name,        fourth_person.short_name,        first_person.path_deps,        second_person.path_deps,        third_person.path_deps,        fourth_person.path_deps,        first_person.new_salary,        second_person.new_salary,        third_person.new_salary,        fourth_person.new_salary        ]test_data = ['Шленский А.', 'Валерьев П.', 'Артуров М.', 'Иванов И.',             'Разработка --> УК --> Автотесты',             'Разработка --> УК',             'Разработка --> УК --> Нефункциональное тестирование --> Автотестирование',             'Разработка',             385056, 314195, 1227366, 173810]for i, d in enumerate(data):    assert_error = f'Не прошла проверка для метода {d.__qualname__} экземпляра с атрибутами {d.__self__.__dict__}'    assert d() == test_data[i], assert_error    print(f'Набор для метода {d.__qualname__} экземпляра класса с атрибутами {d.__self__.__dict__} прошёл проверку')print('Всё ок')